parameters.jsCode:
const raw = $json.content[0].text.replace(/^```(?:json)?|```$/gim, '').trim();
const p = JSON.parse(raw);
const intake = $('Webhook: Proposal Request').item.json;
const analyzer = $('Run Analyzer').item.json;
const esc = s => String(s ?? '').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;','\'':'&#39;'}[c]));
const date = new Date().toLocaleDateString('en-US',{year:'numeric',month:'long',day:'numeric'});
const winsHtml = (p.wins||[]).map(w => `<li>${esc(w)}</li>`).join('');
const findingsHtml = (p.findings||[]).map(f => `<li><strong>${esc(f.category)}:</strong> ${esc(f.issue)} — <em>${esc(f.impact)}</em></li>`).join('');
const planRows = (p.plan||[]).map(r => `<tr><td>${esc(r.weeks)}</td><td>${esc(r.deliverable)}</td><td>${esc(r.service)}</td><td class="price">$${r.price_usd}</td></tr>`).join('');
const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Proposal — ${esc(intake.company)}</title><style>@page{size:A4;margin:18mm 16mm}body{font-family:Helvetica,Arial,sans-serif;color:#111;font-size:11pt;line-height:1.5}.cover{min-height:92vh;background:linear-gradient(135deg,#012169,#051540);color:#fff;padding:60px 50px;page-break-after:always}.cover h1{font-size:38pt;font-weight:900;margin-top:80px;line-height:1.05}.cover h1 span{color:#FF671F}h2{font-size:18pt;color:#012169;border-left:5px solid #FF671F;padding-left:14px;margin:24px 0 10px}ul{padding-left:0;list-style:none}ul li{background:#fff7ed;border-left:3px solid #FF671F;padding:10px 14px;margin-bottom:6px}ul.wins li{background:#ecfdf5;border-left-color:#00A86B}table{width:100%;border-collapse:collapse;margin-top:14px;font-size:10pt}th,td{padding:10px 12px;text-align:left;border-bottom:1px solid #e4e9f2}th{background:#012169;color:#fff}.price{text-align:right;font-weight:800;color:#012169}.total{background:#FF671F;color:#fff;padding:20px;border-radius:10px;font-size:16pt;font-weight:900;text-align:center;margin:20px 0}</style></head><body><section class="cover"><div>NetWeb<strong style="color:#FF671F">Media</strong></div><h1>How we'd grow<br><span>${esc(intake.company)}</span><br>by 10x in 90 days.</h1><p style="color:#C8D4E6;margin-top:24px">Prepared for ${esc(intake.name)} · ${date}</p></section><section><h2>Executive Summary</h2><p>${esc(p.executive_summary)}</p><h2>What's Already Working</h2><ul class="wins">${winsHtml}</ul><h2>Critical Findings</h2><ul>${findingsHtml}</ul><h2>The 90-Day Plan</h2><table><tr><th>Weeks</th><th>Deliverable</th><th>Service</th><th>Investment</th></tr>${planRows}</table><div class="total">Total 90-Day Investment: $${p.total_usd}</div><h2>Expected Outcome</h2><p>${esc(p.expected_outcome)}</p></section></body></html>`;
const filename = `proposal-${intake.company.toLowerCase().replace(/[^a-z0-9]+/g,'-')}-${new Date().toISOString().slice(0,10)}.html`;
return [{ json: { filename, html, lead_email: intake.email, lead_name: intake.name, company: intake.company, total: p.total_usd }, binary: { data: { data: Buffer.from(html).toString('base64'), mimeType: 'text/html', fileName: filename } } }];

